#include <stdio.h>
#include <stdlib.h>
#define MOD 13313
int main() {
    int N, K;
    scanf("%d %d", &N, &K);
    int* colors = (int*)malloc(N * sizeof(int));
    for (int i = 0; i < N; i++) {
        scanf("%d", &colors[i]);
    }
    int* count = (int*)calloc(200001, sizeof(int));
    for (int i = 0; i < N; i++) {
        count[colors[i]]++;
    }
    int** dp = (int**)malloc((200001) * sizeof(int*));
    for (int i = 0; i <= 200000; i++) {
        dp[i] = (int*)malloc((K + 1) * sizeof(int));
    }
    for (int i = 0; i <= 200000; i++) {
        dp[i][0] = 1;
    }
    for (int i = 1; i <= 200000; i++) {
        for (int j = 1; j <= K; j++) {
            for (int k = 0; k <= count[i] && k <= j; k++) {
                dp[i][j] = (dp[i][j] + dp[i - 1][j - k]) % MOD;
            }
        }
    }
    printf("%d\n", dp[200000][K]);
    return 0;
}

